from langchain_core.runnables import RunnableParallel, RunnableLambda
from pydantic import BaseModel, Field

class ReviewFinding(BaseModel):
    lens: str
    issues: list[str]
    severity: str  # "low" | "medium" | "high"

def make_reviewer(lens: str, focus_instruction: str):
    return (
        ChatPromptTemplate.from_messages([
            ("system",
             f"You are a {lens} reviewer. Focus exclusively on {focus_instruction}. "
             f"Return JSON: lens, issues (list of strings), severity (low/medium/high)."),
            ("human", "Code to review:\n```python\n{{code}}\n```"),
        ])
        | llm.with_structured_output(ReviewFinding)
    )

code_review = RunnableParallel(
    correctness=make_reviewer(
        "correctness", "logic errors, off-by-one bugs, wrong return values"
    ),
    security=make_reviewer(
        "security", "injection vulnerabilities, unsafe deserialization, secrets in code"
    ),
    performance=make_reviewer(
        "performance", "O(n²) algorithms, unnecessary I/O, missing caching"
    ),
    readability=make_reviewer(
        "readability", "unclear names, missing docstrings, overly complex expressions"
    ),
)

def aggregate_review(findings: dict[str, ReviewFinding]) -> str:
    lines = []
    for lens, finding in findings.items():
        if finding.issues:
            lines.append(f"[{finding.severity.upper()}] {lens}:")
            for issue in finding.issues:
                lines.append(f"  • {issue}")
    return "\n".join(lines) if lines else "No issues found."

sample_code = """
def get_user(user_id):
    query = f"SELECT * FROM users WHERE id = {user_id}"
    return db.execute(query).fetchone()
"""

findings = code_review.invoke({"code": sample_code})
print(aggregate_review(findings))
